def ensure_template(scripts_dir=None):
    """确保模板docx文件存在，如果没有则从内置base64数据解码生成。返回模板docx文件的完整路径。"""
    if scripts_dir is None:
        scripts_dir = os.path.dirname(os.path.abspath(__file__))
    scripts_dir = os.path.abspath(scripts_dir)
    search_paths = [
        os.path.join(scripts_dir, "模板_民事起诉状.docx"),
        os.path.join(scripts_dir, "..", "templates", "模板_民事起诉状.docx"),
        os.path.join(scripts_dir, "..", "模板_民事起诉状.docx"),
    ]
    for path in search_paths:
        if os.path.exists(path):
            return os.path.abspath(path)
    docx_path = os.path.join(scripts_dir, "模板_民事起诉状.docx")
    docx_bytes = base64.b64decode(_load_template_b64())
    with open(docx_path, "wb") as f:
        f.write(docx_bytes)
    return docx_path

if __name__ == "__main__":
    path = ensure_template()
    if path:
        print("Template ready:", path)
    else:
        print("Template not found")
